#include <bits/stdc++.h>
using namespace std;
int n;
int calc(int x){
    int total=x;
    while(x>=3)total+=x/3,x=x/3+x%3;
    return total;
}
int main(void){
    int l,r,mid,ans;
    cin>>n;
    l=1,r=n,ans=r;
    while(l<=r){
        mid=(l+r)/2;
        if(calc(mid)>=n)ans=mid,r=mid-1;
        else l=mid+1;
    }
    cout<<ans<<endl;
    return false;
}
